import{_ as e,o as n,c as s,ae as o}from"./chunks/framework._o5CmwEE.js";const h=JSON.parse('{"title":"Testing (Unit & E2E)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/testing.md","filePath":"guide/testing.md"}'),r={name:"guide/testing.md"};function i(a,t,l,c,d,g){return n(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="testing-unit-e2e" tabindex="-1">Testing (Unit &amp; E2E) <a class="header-anchor" href="#testing-unit-e2e" aria-label="Permalink to &quot;Testing (Unit &amp; E2E)&quot;">​</a></h1><p>Quality is not an afterthought. Every project comes with a fully configured testing suite.</p><h2 id="unit-testing-jest" tabindex="-1">Unit Testing (Jest) <a class="header-anchor" href="#unit-testing-jest" aria-label="Permalink to &quot;Unit Testing (Jest)&quot;">​</a></h2><p>Powered by <strong>Jest</strong> and <strong>ts-jest</strong> (for TypeScript projects).</p><ul><li><strong>Location</strong>: All unit tests are gathered in the <code>tests/unit/</code> directory, mirroring the <code>src/</code> structure.</li><li><strong>Thresholds</strong>: Coverage gates are set to <strong>70%</strong> for lines and functions to ensure maintainability.</li><li><strong>Commands</strong>: <ul><li><code>npm test</code>: Run all tests.</li><li><code>npm run test:watch</code>: Run tests in watch mode.</li><li><code>npm run test:coverage</code>: Generate a detailed coverage report.</li></ul></li></ul><h2 id="end-to-end-e2e-testing-supertest" tabindex="-1">End-to-End (E2E) Testing (Supertest) <a class="header-anchor" href="#end-to-end-e2e-testing-supertest" aria-label="Permalink to &quot;End-to-End (E2E) Testing (Supertest)&quot;">​</a></h2><p>Focuses on the entire system as a black box, running tests against a real (or mocked) environment.</p><ul><li><strong>Flow</strong>: Uses <strong>Supertest</strong> to make actual HTTP requests to the running service.</li><li><strong>Infrastructure</strong>: E2E tests target the Docker container cluster to ensure networking and DB connectivity are correct.</li><li><strong>Isolation</strong>: Uses a dedicated orchestrator script (<code>scripts/run-e2e.js</code>) to manage the lifecycle of test containers.</li><li><strong>Command</strong>: <code>npm run test:e2e</code></li></ul><h2 id="mocking-standards" tabindex="-1">Mocking Standards <a class="header-anchor" href="#mocking-standards" aria-label="Permalink to &quot;Mocking Standards&quot;">​</a></h2><ul><li><strong>Database</strong>: Pre-configured mocks for Mongoose/Sequelize models.</li><li><strong>Messaging</strong>: Includes logic to mock the <strong>Kafka Singleton Service</strong>, allowing you to test controllers without a live Kafka broker.</li></ul>',10)])])}const m=e(r,[["render",i]]);export{h as __pageData,m as default};
